<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Bouncing Ball Physics Playground</title>
  <style>
    body {
      margin: 0;
      padding: 20px;
      background-color: #1a1a1a;
      color: #e0e0e0;
      font-family: sans-serif;
      display: flex;
      flex-direction: column;
      align-items: center;
      min-height: 100vh;
    }

    h1 {
      margin-bottom: 20px;
      font-weight: normal;
      letter-spacing: 1px;
    }

    #sim-container {
      position: relative;
      box-shadow: 0 4px 20px rgba(0, 0, 0, 0.5);
      border-radius: 8px;
      overflow: hidden;
    }

    canvas#sim {
      background-color: #2a2a2a;
      cursor: crosshair;
      display: block;
    }

    .controls {
      margin-top: 16px;
      display: flex;
      gap: 10px;
    }

    button {
      padding: 8px 16px;
      background-color: #3a3a3a;
      color: #e0e0e0;
      border: none;
      border-radius: 4px;
      cursor: pointer;
      font-size: 14px;
      transition: all 0.2s ease;
    }

    button:hover {
      background-color: #4a4a4a;
      transform: translateY(-1px);
    }

    button:active {
      transform: translateY(1px);
    }

    button#play.active {
      background-color: #2e7d32;
    }
  </style>
</head>
<body>
  <h1>Bouncing Ball Physics Playground</h1>

  <div id="sim-container">
    <canvas id="sim" width="600" height="500"></canvas>
  </div>

  <div class="controls">
    <button id="drop">Drop a ball</button>
    <button id="play">Play/Pause</button>
    <button id="clear">Clear All</button>
  </div>

  <script>
    // Get canvas and context
    const canvas = document.getElementById('sim');
    const ctx = canvas.getContext('2d');

    // Canvas dimensions
    const w = canvas.width;
    const h = canvas.height;

    // Physics parameters
    const GRAVITY = 0.5;
    const RESTITUTION = 0.8; // Energy loss on bounce (0 to 1)
    const FRICTION = 0.995;  // Air resistance

    // Ball storage
    let balls = [];

    // Animation state
    let isPlaying = true;
    let animationId = null;

    // Draw a single ball
    function drawBall(ball) {
      ctx.beginPath();
      ctx.arc(ball.x, ball.y, ball.r, 0, Math.PI * 2);

      // Create gradient for 3D effect
      const gradient = ctx.createRadialGradient(
        ball.x - ball.r/3, ball.y - ball.r/3, ball.r/4,
        ball.x, ball.y, ball.r
      );
      gradient.addColorStop(0, '#64b5f6');
      gradient.addColorStop(1, '#1976d2');

      ctx.fillStyle = gradient;
      ctx.fill();
      ctx.closePath();
    }

    // Draw all balls and canvas background
    function draw() {
      // Clear canvas with dark background
      ctx.fillStyle = '#2a2a2a';
      ctx.fillRect(0, 0, w, h);

      // Draw grid lines for visual reference
      ctx.strokeStyle = '#333';
      ctx.lineWidth = 1;

      // Vertical grid lines every 50px
      for (let x = 0; x < w; x += 50) {
        ctx.beginPath();
        ctx.moveTo(x, 0);
        ctx.lineTo(x, h);
        ctx.stroke();
      }

      // Horizontal grid lines every 50px
      for (let y = 0; y < h; y += 50) {
        ctx.beginPath();
        ctx.moveTo(0, y);
        ctx.lineTo(w, y);
        ctx.stroke();
      }

      // Draw all balls
      for (const ball of balls) {
        drawBall(ball);
      }
    }

    // Update physics for a single ball
    function updateBall(ball) {
      // Apply gravity
      ball.vy += GRAVITY;

      // Apply air resistance
      ball.vx *= FRICTION;
      ball.vy *= FRICTION;

      // Update position
      ball.x += ball.vx;
      ball.y += ball.vy;

      // Check for collisions with canvas boundaries

      // Right wall
      if (ball.x + ball.r > w) {
        ball.x = w - ball.r;  // Clamp to prevent tunneling
        ball.vx *= -RESTITUTION;
      }

      // Left wall
      if (ball.x - ball.r < 0) {
        ball.x = ball.r;  // Clamp to prevent tunneling
        ball.vx *= -RESTITUTION;
      }

      // Floor
      if (ball.y + ball.r > h) {
        ball.y = h - ball.r;  // Clamp to prevent tunneling
        ball.vy *= -RESTITUTION;

        // Prevent endless micro-bouncing when near rest on floor
        if (Math.abs(ball.vy) < GRAVITY * 2) {
          ball.vy = 0;
        }
      }

      // Ceiling
      if (ball.y - ball.r < 0) {
        ball.y = ball.r;  // Clamp to prevent tunneling
        ball.vy *= -RESTITUTION;
      }
    }

    // Update physics for all balls
    function update() {
      for (const ball of balls) {
        updateBall(ball);
      }
    }

    // Main animation loop
    function animate() {
      if (!isPlaying) return;

      update();
      draw();

      animationId = requestAnimationFrame(animate);
    }

    // Start the animation
    animate();

    // API exposed on window.sim
    window.sim = {
      w,
      h,

      balls: () => balls.map(ball => ({ x: ball.x, y: ball.y, vx: ball.vx, vy: ball.vy, r: ball.r })),

      addBall: (x, y, vx = 0, vy = 0, r = Math.random() * 15 + 10) => {
        // Ensure ball starts within canvas bounds
        const radius = Math.max(5, Math.min(r, Math.min(w, h) / 2));
        balls.push({
          x: Math.max(radius, Math.min(x, w - radius)),
          y: Math.max(radius, Math.min(y, h - radius)),
          vx,
          vy,
          r: radius
        });
      },

      clear: () => {
        balls = [];
        draw();
      },

      step: (dt = 1) => {
        // Apply gravity and update positions for one step
        for (const ball of balls) {
          ball.vy += GRAVITY * dt;
          ball.x += ball.vx * dt;
          ball.y += ball.vy * dt;

          // Check collisions with canvas boundaries
          if (ball.x + ball.r > w) {
            ball.x = w - ball.r;
            ball.vx *= -RESTITUTION;
          }

          if (ball.x - ball.r < 0) {
            ball.x = ball.r;
            ball.vx *= -RESTITUTION;
          }

          if (ball.y + ball.r > h) {
            ball.y = h - ball.r;
            ball.vy *= -RESTITUTION;

            // Prevent endless micro-bouncing when near rest on floor
            if (Math.abs(ball.vy) < GRAVITY * 2) {
              ball.vy = 0;
            }
          }

          if (ball.y - ball.r < 0) {
            ball.y = ball.r;
            ball.vy *= -RESTITUTION;
          }
        }

        draw();
      }
    };

    // Event listeners for buttons
    document.getElementById('drop').addEventListener('click', () => {
      const x = w / 2 + (Math.random() * 40 - 20);
      const y = 50;
      window.sim.addBall(x, y, Math.random() * 4 - 2, 0);
    });

    document.getElementById('play').addEventListener('click', () => {
      isPlaying = !isPlaying;

      if (isPlaying) {
        animate();
        document.getElementById('play').classList.add('active');
      } else {
        cancelAnimationFrame(animationId);
        document.getElementById('play').classList.remove('active');
      }
    });

    document.getElementById('clear').addEventListener('click', () => {
      window.sim.clear();
    });

    // Canvas click to add ball
    canvas.addEventListener('click', (e) => {
      const rect = canvas.getBoundingClientRect();
      const x = e.clientX - rect.left;
      const y = e.clientY - rect.top;

      // Random radius between 10 and 30 pixels
      const r = Math.random() * 20 + 10;

      window.sim.addBall(x, y, (Math.random() - 0.5) * 10, (Math.random() - 0.5) * 10, r);
    });

    // Initial ball for demonstration
    window.sim.addBall(w / 2, h / 3, 3, 0, 20);
  </script>
</body>
</html>
